import React, { useState, useEffect, useRef } from 'react';
import './App.css';
import { Save, Calendar, FileText, ChevronRight, Flag, Clock, Info, Loader, Trash2, X } from 'lucide-react';

function App() {
  const [formData, setFormData] = useState({
    week: '',
    type: '',
    date: '',
    action: ''
  });

  const [weeks, setWeeks] = useState([]);
  const [types, setTypes] = useState([]);
  const [actions, setActions] = useState([]);
  const [expandedNodes, setExpandedNodes] = useState(new Set());
  const [contextMenu, setContextMenu] = useState({ visible: false, x: 0, y: 0, actionId: null });
  const [actionStatuses, setActionStatuses] = useState({});
  const [excludedFromReport, setExcludedFromReport] = useState(new Set());
  const [errors, setErrors] = useState({
    week: false,
    type: false,
    date: false,
    action: false
  });
  const dateInputRef = useRef(null);
  const contextMenuRef = useRef(null);

  useEffect(() => {
    // Load weeks from text file
    fetch('/data/weeks.txt')
      .then(response => response.text())
      .then(data => {
        const weekList = data.split('\n').filter(line => line.trim());
        setWeeks(weekList);
      })
      .catch(error => {
        console.error('Error loading weeks:', error);
        // Fallback data
        setWeeks(['1. Hafta', '2. Hafta', '3. Hafta', '4. Hafta']);
      });

    // Load types from text file
    fetch('/data/types.txt')
      .then(response => response.text())
      .then(data => {
        const typeList = data.split('\n').filter(line => line.trim());
        setTypes(typeList);
      })
      .catch(error => {
        console.error('Error loading types:', error);
        // Fallback data
        setTypes(['Planlama', 'Geliştirme', 'Test', 'Dokümantasyon']);
      });
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear error when user enters data
    if (value.trim()) {
      setErrors(prev => ({ ...prev, [name]: false }));
    }
  };

  const handleCalendarClick = () => {
    dateInputRef.current?.showPicker();
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const newErrors = {
      week: !formData.week,
      type: !formData.type,
      date: !formData.date,
      action: !formData.action
    };

    setErrors(newErrors);

    if (Object.values(newErrors).some(error => error)) {
      return;
    }

    const newAction = {
      id: Date.now(),
      ...formData,
      timestamp: new Date().toLocaleString('tr-TR')
    };

    setActions(prev => [...prev, newAction]);

    // Auto-expand the week for the new action
    setExpandedNodes(prev => new Set([...prev, formData.week]));

    // Reset form and errors
    setFormData({
      week: '',
      type: '',
      date: '',
      action: ''
    });
    setErrors({
      week: false,
      type: false,
      date: false,
      action: false
    });
  };

  const toggleNode = (nodeId) => {
    setExpandedNodes(prev => {
      const newSet = new Set(prev);
      if (newSet.has(nodeId)) {
        newSet.delete(nodeId);
      } else {
        newSet.add(nodeId);
      }
      return newSet;
    });
  };

  const handleContextMenu = (e, actionId) => {
    e.preventDefault();
    setContextMenu({
      visible: true,
      x: e.pageX,
      y: e.pageY,
      actionId: actionId
    });
  };

  const handleCloseContextMenu = () => {
    setContextMenu({ visible: false, x: 0, y: 0, actionId: null });
  };

  const handleSetStatus = (status) => {
    setActionStatuses(prev => ({ ...prev, [contextMenu.actionId]: status }));
    handleCloseContextMenu();
  };

  const handleRemoveFromReport = () => {
    setExcludedFromReport(prev => new Set([...prev, contextMenu.actionId]));
    handleCloseContextMenu();
  };

  const handleDeleteAction = () => {
    setActions(prev => prev.filter(a => a.id !== contextMenu.actionId));
    handleCloseContextMenu();
  };

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (contextMenuRef.current && !contextMenuRef.current.contains(e.target)) {
        handleCloseContextMenu();
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  const groupActionsByWeek = () => {
    const grouped = {};
    actions.filter(a => !excludedFromReport.has(a.id)).forEach(action => {
      if (!grouped[action.week]) {
        grouped[action.week] = [];
      }
      grouped[action.week].push(action);
    });
    return grouped;
  };

  const groupedActions = groupActionsByWeek();

  return (
    <div className="app-container">
      <header className="header">
        <h1>Haftalık Aksiyon Takibi</h1>
      </header>

      <div className="content">
        <div className="left-section">
          <div className="card">
            <h2 className="card-title">Yeni Aksiyon Ekle</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Hafta</label>
                <select
                  className={`form-select ${errors.week ? 'error' : ''}`}
                  name="week"
                  value={formData.week}
                  onChange={handleInputChange}
                >
                  <option value="">Hafta seçin...</option>
                  {weeks.map((week, index) => (
                    <option key={index} value={week}>{week}. Hafta</option>
                  ))}
                </select>
                {errors.week && <span className="error-text">Lütfen hafta seçin</span>}
              </div>

              <div className="form-group">
                <label className="form-label">Tür</label>
                <select
                  className={`form-select ${errors.type ? 'error' : ''}`}
                  name="type"
                  value={formData.type}
                  onChange={handleInputChange}
                >
                  <option value="">Tür seçin...</option>
                  {types.map((type, index) => (
                    <option key={index} value={type}>{type}</option>
                  ))}
                </select>
                {errors.type && <span className="error-text">Lütfen tür seçin</span>}
              </div>

              <div className="form-group">
                <label className="form-label">Tarih</label>
                <div className="input-with-icon">
                  <input
                    type="date"
                    className={`form-control ${errors.date ? 'error' : ''}`}
                    name="date"
                    ref={dateInputRef}
                    value={formData.date}
                    onChange={handleInputChange}
                    placeholder="gg.aa.yyyy"
                  />
                  <Calendar className="input-icon" size={18} onClick={handleCalendarClick} style={{ cursor: 'pointer', pointerEvents: 'auto' }} />
                </div>
                {errors.date && <span className="error-text">Lütfen tarih girin</span>}
              </div>

              <div className="form-group">
                <label className="form-label">Aksiyon</label>
                <textarea
                  className={`form-textarea ${errors.action ? 'error' : ''}`}
                  name="action"
                  value={formData.action}
                  onChange={handleInputChange}
                  placeholder="Aksiyonu detaylı olarak yazın..."
                />
                {errors.action && <span className="error-text">Lütfen aksiyon açıklaması girin</span>}
              </div>

              <button type="submit" className="btn btn-primary">
                <Save size={16} />
                Kaydet
              </button>
            </form>
          </div>
        </div>

        <div className="right-section">
          <div className="card">
            <h2 className="card-title">Haftalık Rapor</h2>
            <div className="report-section">
              <div className="report-content">
                <p className="report-text">
                  Bu hafta toplam {actions.length} aksiyon kaydedildi.
                </p>
              </div>
            </div>
          </div>

          <div className="card">
            <h2 className="card-title">Ekip Aksiyonları</h2>
            {actions.length === 0 ? (
              <div className="empty-state">
                <FileText className="empty-state-icon" size={48} />
                <h3>Henüz kayıt yok</h3>
                <p>Yeni bir aksiyon ekleyerek başlayın</p>
              </div>
            ) : (
              <div className="tree-view">
                {Object.entries(groupedActions).map(([week, weekActions]) => (
                  <div key={week} className="tree-node">
                    <div 
                      className="tree-node-header"
                      onClick={() => toggleNode(week)}
                    >
                      <span className="tree-node-title">{week}. Hafta ({weekActions.length} aksiyon)</span>
                      <ChevronRight 
                        className={`tree-node-toggle ${expandedNodes.has(week) ? 'expanded' : ''}`} 
                        size={18} 
                      />
                    </div>
                    <div className={`tree-node-content ${!expandedNodes.has(week) ? 'hidden' : ''}`}>
                      {weekActions.map(action => (
                        <div 
                          key={action.id} 
                          className={`tree-action-row ${actionStatuses[action.id] ? `status-${actionStatuses[action.id]}` : ''}`}
                          onContextMenu={(e) => handleContextMenu(e, action.id)}
                        >
                          <span className="tree-action-type">{action.type}</span>
                          <span className="tree-action-separator">-</span>
                          <span className="tree-action-text">{action.action}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {contextMenu.visible && (
        <div
          ref={contextMenuRef}
          className="context-menu"
          style={{ top: contextMenu.y, left: contextMenu.x }}
        >
          <div className="context-menu-item" onClick={() => handleSetStatus('highlight')}>
            <Flag size={16} className="context-menu-icon highlight" />
            <span>Vurgula</span>
          </div>
          <div className="context-menu-item" onClick={() => handleSetStatus('lowlight')}>
            <Flag size={16} className="context-menu-icon lowlight" />
            <span>Düşük Öncelik</span>
          </div>
          <div className="context-menu-item" onClick={() => handleSetStatus('waiting')}>
            <Clock size={16} className="context-menu-icon waiting" />
            <span>Harici Destek Bekleniyor</span>
          </div>
          <div className="context-menu-item" onClick={() => handleSetStatus('information')}>
            <Info size={16} className="context-menu-icon information" />
            <span>Bilgi</span>
          </div>
          <div className="context-menu-item" onClick={() => handleSetStatus('progress')}>
            <Loader size={16} className="context-menu-icon progress" />
            <span>Devam Ediyor</span>
          </div>
          <div className="context-menu-separator" />
          <div className="context-menu-item danger" onClick={handleRemoveFromReport}>
            <X size={16} className="context-menu-icon" />
            <span>Haftalık Rapordan Çıkar</span>
          </div>
          <div className="context-menu-item danger" onClick={handleDeleteAction}>
            <Trash2 size={16} className="context-menu-icon" />
            <span>Sil</span>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
